SELECT user_email
FROM users
WHERE user_email = #{userEmail}

SELECT user_phone
FROM users
WHERE user_phone = #{userPhone}

SELECT user_nickname
FROM users
WHERE user_nickname = #{userNickname}

SELECT user_id, user_email, user_password
FROM users
WHERE user_email = #{userEmail}

mapper.update:
UPDATE users
SET user_profile_image = #{userProfileImage},
    user_nickname = #{userNickname},
    user_bio = #{userBio}
WHERE user_id = #{userId}

UPDATE users
SET user_status = 'DEACTIVE'
WHERE user_id = #{userId}

mapper.select:
SELECT users.user_id, users.user_email, users.user_name, users.user_nickname, users.user_phone, users.user_birth_date, users.user_profile_image, users.user_bio, users.user_created_at
FROM users
WHERE user_id = #{userId}

SELECT activity_date FROM user_daily_activity WHERE user_id = #{userId}
AND activity_date >= date_trunc('week', now() - interval '1 week') - interval '1 day' AND activity_date <= now()
ORDER BY activity_date
